var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"Counterside Variable Depth Coordinates\\n<color=#ff3636>Philharmonic Hall</color>","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 야크샤 전대, 카르데나스 전대.\\n강습 작전 수행 중.\\n작전명 <color=#ffd34c>트러블 슈팅</color>","JPN":"管理局ヤクシャー戦隊、カルデナス戦隊。\\n強襲作戦遂行中。\\n作戦名<color=#ffd34c>トラブルシューティング</color>","ENG":"Administration Yaksha Division, Cardenas Division.\\nConducting an Assault Operation.\\nOperation Name <color=#ffd34c>Troubleshooting</color>","TWN":"舊管理局 夜叉戰隊、卡特納斯戰隊\\n執行強襲作戰中。\\n作戰名稱 <color=#ffd34c>故障排除</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"싫어……! 내 머릿속을 헤집지 마!! 싫어어어어!!","JPN":"嫌だ……！　頭ん中を掻きまわすな！！　止めろぉぉぉ！！","ENG":"No...! Get out of my head!! Stop!!","TWN":"走開……！滾出我的腦袋！！討厭！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"멈춰!! 아군이다! 능력을 사용하지 마!","JPN":"止めろ！！　味方だ！　能力を使うな！","ENG":"Stop!! We’re allies! Don’t use your powers!","TWN":"住手！！是我方人員！不要使用能力！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"틀렸습니다! 이미 제정신이 아니에요! 사살해야 합니다!!","JPN":"だめです！　正気を失っています！　殺さなければ！！","ENG":"Too late! He’s already lost his mind! We must shoot!","TWN":"不行！他現在已經神智不清！必須立刻擊斃！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"내 배 안에 벌레가 들어 있어…… 내, 내 배 안에서 그게 꿈틀거리다가……!","JPN":"腹の中に虫が入っている……ぼ、僕の腹の中であれがうごめいて……！","ENG":"There’s a bug in my stomach... It’s, it’s wiggling around in my stomach...!","TWN":"我肚子裡有蟲……蟲在我的肚子裡蠕動……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"정신 차려, 이 멍청아! 그건 놈들이 덮어 씌운 기억이야! 속지 마!!","JPN":"しっかりしろ、バカ野郎！　それはやつらが上書きした記憶だ！　騙されるな！！","ENG":"Pull yourself together, idiot! That’s just a memory they’ve planted into your brain! Don’t be fooled!","TWN":"傻瓜，你清醒一點！這是那些傢伙植入的記憶！不可以上當！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 진정제 주사해! 저 놈 자기 손으로 배 가르는 꼴 보고 싶어?!","JPN":"早く鎮静剤を打て！　あいつが自分の腹を切るところが見たいのか！？","ENG":"Somebody, sedate him! Do you want to see him rip his stomach apart with his own hands?!","TWN":"立刻給他打鎮定劑！還是你想看他把自己的肚皮挖破？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지휘부에! 멘탈 프린팅을 촉발하는 파동이 검출되었습니다!</color>","JPN":"<color=#ffd34c>司令部へ！　メンタル・プリンティングを起こす波動が検出されました！</color>","ENG":"<color=#ffd34c>Headquarters! A wave triggering Mental Printing has been detected!</color>","TWN":"<color=#ffd34c>指揮部感應到觸發智力複印的波動！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>첩보가 틀렸습니다! 마에스트로가 아직 이곳에……!</color>","JPN":"<color=#ffd34c>諜報が間違っていました！　マエストロがまだここに……！</color>","ENG":"<color=#ffd34c>Our intel was wrong! Maestra is still here...!</color>","TWN":"<color=#ffd34c>情報有誤！指揮家尚未……！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국 놈들은 모두 죽여버려! 안돼, 쏘지 마! 죽여 버려! 함장님! 사, 살려……!","JPN":"管理局のやつらは全員死んじまえ！　止めろ、撃つな！　殺せ！　艦長！　た、助け……！","ENG":"Kill everyone from the Administration! Wait, don’t shoot! DIE! Leader! Sa-Save M...!","TWN":"把管理局的傢伙全都殺光！不可以，別開槍！殺光！艦長！救我……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런 말도 안 되는 일이……!","JPN":"そんな馬鹿な……こんなことに！","ENG":"Impossible...!","TWN":"該死……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제9 포격전대 <color=#ffd34c>메이즈</color>\\n전대장 류드밀라","JPN":"管理局第9砲撃戦隊<color=#ffd34c>メイズ</color>\\n戦隊長リュドミラ","ENG":"Administration 9th Artillery Division <color=#ffd34c>Maze</color>\\nCommander Lyudmila","TWN":"管理局第9炮擊戰隊<color=#ffd34c>梅茲</color>\\n戰隊長盧德米拉"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"모네카! 뭔가 대책이 없나!","JPN":"モネカ！　何か対策はないのか！","ENG":"Moneka! Is there anything we can do?!","TWN":"莫奈卡！有什麼對策嗎！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"연합전대가 이렇게 허무하게 당하고 있는 꼴을 지켜만 볼 수는 없단 말이다!","JPN":"連合戦隊がこんなにあっけなくやられているところを見過ごすわけにはいかないだろう！","ENG":"We can't stand by and watch the coalition divisions suffer in vain!","TWN":"我們不能就這樣眼睜睜地看著聯合戰隊白白犧牲！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"진정하세요, 메이즈 전대장님!","JPN":"落ち着いてください、メイズ戦隊長！","ENG":"Calm down, Maze Division Commander!","TWN":"請冷靜，梅茲戰隊長！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 전대급 전술지원 <color=#ffd34c>AI</color>\\n모네카","JPN":"管理局戦隊級戦術支援<color=#ffd34c>AI</color>\\nモネカ","ENG":"Administration Division Tactical Support <color=#ffd34c>AI</color>\\nMoneka","TWN":"管理局戰隊戰術支援<color=#ffd34c>AI</color>\\n莫奈卡"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"진정하라고? 전우들의 비명을 듣고 있는데 어떻게 진정할 수 있지!?","JPN":"落ち着けだと？　戦友たちの悲鳴を聞いて落ち着くことなどできるはずないだろう！","ENG":"Calm down?! How can I be calm when I hear the screams of our comrades?!","TWN":"冷靜？聽著戰友們的慘叫聲，你讓我怎麼冷靜？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런 탁상공론을 하는 동안에도 전우들의 목숨은 희생되고 있다!","JPN":"こうしている間にも戦友たちの命が犠牲になっているんだ！","ENG":"While we're here discussing unimportant things, the lives of our comrades are being sacrificed!","TWN":"就在我們紙上談兵的時候，犧牲的戰友越來越多了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"급한 마음은 이해하지만, 지금은 연합전대를 구하러 갈 수 있는 상황이 아니에요!","JPN":"お気持ちはわかりますが、今は連合戦隊を助けに行ける状況ではありません！","ENG":"I understand your frustration, but now is not the time to go rescue our coalition divisions!","TWN":"我理解你焦急的心情，但現在的情況，不適合去救援聯合戰隊！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국은 현재 대기권 너머의 궤도병기로부터 폭격을 당하고 있습니다.","JPN":"現在、管理局は大気圏の外にある軌道兵器から砲撃を受けています。","ENG":"The Administration is currently under orbital bombardment from beyond the atmosphere.","TWN":"管理局目前正在遭受大氣層外軌道武器的轟炸。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"하이브 컨트롤의 분석 결과, 적기는 <color=#ffd34c>이터니움 드라이브</color>의 파장을 검출. 공격하는 패턴을 보이고 있어요.","JPN":"ハイブコントロールの分析結果、敵機は<color=#ffd34c>エタニウムドライブ</color>の波長を検出、攻撃するパターンを見せています。","ENG":"According to the Hive Control's analysis, the enemy is showing patterns of detecting <color=#ffd34c>Eternium Drive</color> wavelength and attacking.","TWN":"根據巢穴控制系統分析的結果，敵機表現出<color=#ffd34c>永恆之金驅動器</color>的波長，並處於攻擊模式。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이에 따라, 작전 중이던 관리국 차원함선 4기가 차례로 격추당했고요.","JPN":"そのため、作戦中だった管理局の次元艦船4機が続けて撃墜されました。","ENG":"As a result, four of the Administration's dimensional ships were consequently shot down one after the other.","TWN":"正因如此，相繼已有四艘正在作戰的管理局次元艦船被擊落。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이터니움 드라이브의 파장을 검출한다고?","JPN":"エタニウムドライブの波長を検出しただと？","ENG":"It's detecting the Eternium Drive wavelength?","TWN":"檢測到了永恆之金驅動器的波長？"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면…… 적기의 목적은 아군의 다이브 저지인가?","JPN":"ということは……敵機の目的は味方のダイブ阻止だということか？","ENG":"Then... Is the enemy's purpose to stop our dive?","TWN":"這麼說……敵機的目的是阻止我們躍入嗎？"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그렇습니다, 전대장님.","JPN":"その通りです、戦隊長。","ENG":"Correct, Commander.","TWN":"是的，戰隊長。"},"stage":{"bg":"MS_1204_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>필하모닉 홀</color>은 심도가 확정되지 않은 가변심도에 있는 이면세계.","JPN":"<color=#ffd34c>フィルハーモニーホール</color>は深度が定まらない可変深度に存在する裏世界。","ENG":"<color=#ffd34c>Philharmonic Hall</color> is the Counterside with the variable depth coordinates, where the depth is not fixed.","TWN":"<color=#ffd34c>管弦樂廳</color>是一個處於可變深度的異界。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이 좌표에 다다르기 위해서는 반드시 차원함선을 통한 확정 차원 도약이 필요해요.","JPN":"この座標に辿り着くためには､次元艦船による確定次元跳躍が必要になります。","ENG":"In order to reach these coordinates, a guaranteed dimension jump in a dimensional ship is required.","TWN":"要抵達那個座標，就必須使用次元艦船進行躍遷。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이런 상황에서 적기가 함선만을 노리는 이유는 관리국의 다이브 저지가 틀림없어요!","JPN":"今のような状況で敵機が艦船だけを狙っているのは､管理局のダイブを阻止するために間違いありません！","ENG":"So, the reason for the enemy targeting only the ships is to prevent the Administration's dive!","TWN":"這種情況下，敵機瞄準艦船的原因，無非便是為了阻止管理局的躍入！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이상하지 않나!","JPN":"しかし理解できない！","ENG":"But doesn't that seem strange?!","TWN":"但你不覺得奇怪嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대기권 너머 우주에 있는 적기는 지상의 함선을 노릴 정도로 가까이 접근했어.","JPN":"宇宙の敵機は地上の艦船を狙えるほど近くまで接近していた。","ENG":"The enemy ship above the atmosphere has gotten close enough to target our ships on the ground.","TWN":"位於外太空的敵方戰艦，能夠瞄準艦船，就表示已經很接近了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국 <color=#ffd34c>전략위성</color>은 어째서 적기를 관측하지 못한 거지?","JPN":"管理局の<color=#ffd34c>戦略衛星</color>は、なぜ敵機を観測できなかったのだ？","ENG":"How was the enemy ship not detected by the Administration's <color=#ffd34c>strategic satellite</color>?","TWN":"管理局的<color=#ffd34c>戰略衛星</color>怎麼會偵測不到它們？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그게…….","JPN":"それは……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"적기로부터 접수된 식별신호가…… 바로 그 전략위성으로 찍히고 있어서요.","JPN":"敵機の識別信号が……管理局の戦略衛星のものになっていたのです。","ENG":"The identification signal received from the enemy ship is... showing up as that strategic satellite.","TWN":"那是因為接收到的敵機識別訊號……就是從那顆戰略衛星上傳過來的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐라고……!?","JPN":"何だと……！？","ENG":"What...?!","TWN":"你說什麼？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"낭패로군. 모더레이터와 비슷한 케이스인가?","JPN":"不覚だな。それはモデレーターのようなケースなのか。","ENG":"This is a disaster. Is this a similar case to the Moderator?","TWN":"糟糕……是與仲裁者相似的情況嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 세계의 침식률 상승에 따른, 정보오염으로 추정됩니다.","JPN":"はい。世界の侵食率上昇による情報汚染だと推測されます。","ENG":"Correct. We assume it is data corruption as the world's corruption rate rises.","TWN":"是的。據推測，應該是由於世界侵蝕速度加快而造成的資訊污染。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"기체에 엑세스해보면 확실해지겠지만, 우주 잔류 침식파에 오래 노출된 탓이겠죠.","JPN":"詳細は機体にアクセスすればわかると思いますが……宇宙の残留侵食波に長く曝されていたためでしょう。","ENG":"We'll know for sure once we have access to the satellite, but it may be due to the prolonged exposure of Corruption rays remaining in space.","TWN":"需要進入機體才能進一步的確認，但此次情況很有可能是長時間暴露在太空殘留侵蝕波中所導致的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국은 현재, 대기권 너머의 해당 적기를 향해 미사일 요격을 수행하고 있습니다만.","JPN":"管理局は現在、大気圏外にある当該敵機へ向け、ミサイル迎撃を試みていますが……","ENG":"The Administration is currently firing missiles toward the enemy beyond the atmosphere.","TWN":"目前，管理局正在對大氣層外的敵機進行導彈攔截。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"전략위성의 능동방어 체계 때문에 요격이 쉽지 않은 상황입니다.","JPN":"戦略衛星の能動防御システムのせいで難航している状況です。","ENG":"But because of the strategic satellite's active defense system, shooting it down is not easy.","TWN":"不過，由於戰略衛星的主動防禦系統，想要擊落它並不容易。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이터니움 드라이브를 표준 동력원으로 쓰는 관리국 기체로는 접근조차 허용되지 않고요.","JPN":"エタニウムドライブを標準動力源としている管理局の機体では、接近すらままならないですし。","ENG":"It also prohibits access to Administration aircraft that use Eternium Drive as their primary power source.","TWN":"並且它還禁止使用永恆之金驅動器的管理局飛行器靠近。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그야말로 난공불락……. 적기는 마치 성벽을 두른 요새와 같아요.","JPN":"まさに難攻不落……敵機はまるで城壁に囲まれた要塞そのものです。","ENG":"It's practically impenetrable... It's as if the enemy ship is a fortified stronghold.","TWN":"說是銅牆鐵壁也不為過……敵機就像一座四周築有圍牆的堡壘。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이 상황을 타파하지 못하면, 필하모닉 홀에 돌입하는 것은 불가능합니다.","JPN":"今の状況を打開しないと、フィルハーモニーホールに突入することは不可能です。","ENG":"If we don't overcome this situation, it will be impossible for us to infiltrate Philharmonic Hall.","TWN":"如果不能打破這種局面，就無法進入管弦樂廳。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 전우들이 죽는 꼴을 구경만 하고 있을 수는 없지 않나!","JPN":"だからといって、戦友たちが死んでいく姿を傍観しているわけにはいかない！","ENG":"But we can't just stand here and watch our comrades die!","TWN":"難道我們就要眼睜睜地看著戰友送死嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"골든 타임은 이미 지났어!","JPN":"既にゴールデンタイムは過ぎているのだ！","ENG":"We don't have time to hesitate!","TWN":"我們已經錯過了黃金時間！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"필하모닉 홀과 현실 간의 시간 격차를 고려해도, 앞으로 1시간이 데드라인이야!","JPN":"フィルハーモニーホールと現実での時間差を考慮しても、デッドラインはあと1時間に迫っている！","ENG":"Taking into account the time gap between Philharmonic Hall and the Normalside, the deadline is just an hour away!","TWN":"算上管弦樂廳與現實之間的時差，我們只剩下1小時了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그건 알고 있지만…….","JPN":"それはわかっていますが……","ENG":"I know that already, but...","TWN":"我知道，但是……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"우리가 우주로 나가겠다.","JPN":"私たちが宇宙に出る。","ENG":"We'll go out to space.","TWN":"我們會去太空。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이 목소리는……!?","JPN":"この声は……！？","ENG":"That voice...!","TWN":"這聲音是……？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"펜릴 전대가 우주로 가서 궤도병기를 요격하겠다.","JPN":"フェンリル戦隊が宇宙に向かい、軌道兵器を迎撃する。","ENG":"The Fenrir Division will go to space and intercept the orbital weapon.","TWN":"芬里爾戰隊會前往太空，攔截軌道武器。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제1 강습전대 <color=#ffd34c>펜릴</color>\\n전대장 힐데","JPN":"管理局第1強襲戦隊<color=#ffd34c>フェンリル</color>\\n戦隊長ヒルデ","ENG":"Administration 1st Assault Division <color=#ffd34c>Fenrir</color>\\nCommander Hilde","TWN":"管理局第一強襲戰隊<color=#ffd34c>芬里爾</color>\\n戰隊長希爾德"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"류드밀라, 너는 다른 전대와 함께 필하모닉 홀에 돌입하여 연합전대를 구출하도록.","JPN":"リュドミラ、お前は他の戦隊と共にフィルハーモニーホールに突入し、連合戦隊を救出しろ。","ENG":"Lyudmila, you and the other divisions head to Philharmonic Hall and rescue the coalition divisions.","TWN":"盧德米拉，你和其他戰隊一起攻入管弦樂廳，營救聯合戰隊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무리입니다!","JPN":"無茶なことを言わないでください！","ENG":"That's putting you through too much!","TWN":"太勉強了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"펜릴은 연속된 작전 투입으로 벌써 일주일째 수면조차 취하지 못한 상태이지 않습니까!","JPN":"フェンリルは連続出撃で、もう1週間もまともに睡眠すら取れていない状況ではありませんか！","ENG":"Fenrir has been continuously deployed on missions and hasn't been able to sleep for a week!","TWN":"芬里爾戰隊因為連續投入作戰，已經一週沒有合眼休息了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"애초에 지휘부가 이번 강습 작전에 펜릴을 제외한 이유도……!","JPN":"そもそも、司令部が今回の強襲作戦からフェンリルを外した理由も……！","ENG":"The reason why the Headquarters excluded Fenrir from this operation is–!","TWN":"這也是指揮部將芬里爾排除在此次突襲作戰之外的原因……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"상관없다.","JPN":"構わん。","ENG":"It doesn't matter.","TWN":"不要緊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"나도, 우리 전대원들도 겨우 이 정도로 쓰러질 정도로 약하지 않아.","JPN":"私も戦隊員たちもこの程度で倒れるほど軟ではない。","ENG":"My division and I are strong enough to handle this.","TWN":"我和我的隊員沒有那麼弱。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"무엇보다 관리국은 곧 오퍼레이션 <color=#ffd34c>클리포트 게임</color>을 앞두고 있다.","JPN":"なにより管理局はオペレーション<color=#ffd34c>クリフォトゲーム</color>を控えている。","ENG":"Above all, the Administration will soon be starting Operation <color=#ffd34c>Qliphoth Game</color>.","TWN":"最重要的是，管理局即將展開<color=#ffd34c>逆卡巴拉遊戲</color>。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"이 이상, 전력을 상실하는 건 막아야 해.","JPN":"これ以上の戦力喪失は防がなければならない。","ENG":"We must prevent all losses as much as possible.","TWN":"在此之前，必須阻止兵力的損失。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"잠깐만요, 펜릴 전대장님!","JPN":"お待ちください、フェンリル戦隊長！","ENG":"Hold on, Fenrir Division Commander!","TWN":"等一下，芬里爾戰隊長！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L43_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"하이브 컨트롤의 인과율 연산 결과가 접수되었습니다.","JPN":"ハイブコントロールの因果律の演算結果が受信されました。","ENG":"Hive Control's causality calculation results have just come in.","TWN":"我已接收到巢穴控制系統的因果計算結果。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"테라브레인 단말 과반수가 펜릴 전대가 빠지면, 필하모닉 홀 공략이 실패한다고 예측하고 있어요!","JPN":"テラブレイン端末の過半数が、フェンリル戦隊が抜けるとフィルハーモニーホールの攻略は失敗すると予測しています！","ENG":"The majority of Terrabrain terminals predict that the attack on Philharmonic Hall will fail without the Fenrir Division!","TWN":"超過半數的特拉大腦終端預測認為，如果芬里爾戰隊離開，我們攻佔管弦樂廳的行動將會以失敗告終！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"연합전대의 구원을 위해서라도 펜릴 전대는 반드시 이곳에 남아있어야 합니다.","JPN":"連合戦隊を救うためにも、フェンリル戦隊は必ずここに残らないといけません。","ENG":"In order to rescue the coalition divisions, the Fenrir Division must remain here.","TWN":"若是要營救援聯合戰隊，芬里爾戰隊就必須留在這裡。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런……!?","JPN":"そんな……！？","ENG":"That's...!","TWN":"那……？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 하이브 컨트롤은 처음부터 펜릴의 작전투입을 상정하고 있었다는 말인가!","JPN":"では、ハイブコントロールは最初からフェンリルの作戦投入を想定していたということか！","ENG":"Then Hive Control was expecting that the Fenrir Division would be involved in this operation from the beginning?!","TWN":"那麼，意思是巢穴控制系統一開始就已經設想過讓芬里爾參與作戰了嗎！？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"게다가 아무리 펜릴이라고 해도, 우주에 갈 수 있는 수단이 없는 이상…… ","JPN":"それにいくらフェンリルでも、宇宙に行ける手段がない限り…… ","ENG":"Also, unless there's a way for the Fenrir Division to go out into space...","TWN":"而且，就算是芬里爾，想要前往太空也……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"지휘부에! 들립니까! 야크샤 전대의 앨리스입니다!","JPN":"司令部へ！　聞こえますか！　こちらはヤクシャー戦隊のアリス！","ENG":"Headquarters, do you copy?! This is Alice of the Yaksha Division!","TWN":"指揮部！能聽見嗎？這裡是夜叉戰隊的艾莉絲！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제4 수색전대 <color=#ffd34c>야크샤</color>\\n전대장 앨리스","JPN":"管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>\\n戦隊長アリス","ENG":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color>\\nCommander Alice","TWN":"管理局第4偵察戰隊<color=#ffd34c>夜叉</color>\\n戰隊長艾莉絲"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어라? 야크샤 전대장님이 어떻게……? 부상을 입었다고 들었는데……?","JPN":"え……？　ヤクシャー戦隊長がどうして……？　怪我をされたと聞きましたけど……？","ENG":"Huh? Yaksha Division Commander, are you okay...? I heard you were injured…?","TWN":"嗯？夜叉戰隊長怎麼……？我聽說你負傷了……？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 전대장? 자네 지금 어디지!?","JPN":"アリス戦隊長？　今どこにいる？","ENG":"Commander Alice? Where are you right now?!","TWN":"艾莉絲戰隊長？你現在在哪裡？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이것저것 설명할 시간 없습니다!","JPN":"今は、細かいことを説明する時間がありません！","ENG":"There's no time to explain!","TWN":"沒時間解釋那麼多了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"상황은 대강 들었습니다! 제가 우주로 올라가 궤도병기를 요격하겠습니다!","JPN":"話はだいたい聞きました。アタシが宇宙に出て軌道兵器を迎撃します！","ENG":"I heard about the situation! I'll go to space and bring down the orbital weapon!","TWN":"情況我大概聽說了！我會上太空攔截軌道武器！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"무슨 말씀이세요, 전대장님!","JPN":"何を言っているのですか、戦隊長！","ENG":"What are you talking about, Commander?!","TWN":"你說什麼，戰隊長？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국 장비 없이, 1시간 내로 어떻게 우주로 간다는 거예요?","JPN":"管理局の装備無しで1時間以内に宇宙に出るなんて不可能です！","ENG":"How are you supposed to go to space in less than an hour without gear from the Administration?","TWN":"在沒有任何管理局裝備的情況下，你要怎麼在1小時內抵達太空？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"아는 사람을 통해서 시험용 우주선을 빌렸어! 자세히 설명하려면 복잡해!","JPN":"とある筋から試作用の宇宙船を借りたんだ！　詳しく話すと長くなる！","ENG":"I borrowed a test space shuttle through someone I know! It's complicated to explain it all!","TWN":"我透過認識的人借了一艘實驗用太空船！詳細解釋起來比較複雜！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이터니움 드라이브를 사용하지 않으니까, 그 망할 고철 덩어리한테 접근할 수 있겠지!","JPN":"エタニウムドライブを使ってないから、あのチンケな鉄くずの塊にも接近できるはずだ！","ENG":"It doesn't use Eternium Drive, so I'll be able to reach that hunk of junk!","TWN":"只要不使用永恆之金驅動器，就可以靠近那該死的鐵塊了吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"성공한다면, 필하모닉 홀에 빠진 연합전대를 구원하러 갈 수 있을 거야!","JPN":"成功したら、フィルハーモニーホールにいる連合戦隊を助けにいける！","ENG":"If I succeed, you'll be able to rescue the coalition divisions in Philharmonic Hall!","TWN":"如果成功，你們就可以去救困在管弦樂廳裡的聯合戰隊了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무모해, 앨리스! 성공확률이 너무 희박하지 않나!","JPN":"アリス、それはあまりにも無謀だ！　成功率が低すぎる！","ENG":"That's reckless, Alice! The chances of succeeding are slim to none!","TWN":"這太魯莽了，艾莉絲！這麼做成功的可能性微乎及微！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무기도 탑재할 수 없는 시험용 우주선으로 어떻게 적기를 파괴할 셈이지?","JPN":"武器も搭載できない試作用の宇宙船で、どうやって敵機を破壊するというのだ！","ENG":"How are you going to destroy the enemy ship with a test space shuttle that can't carry any weapons?!","TWN":"實驗用太空船連武器都無法搭載，你要用什麼來摧毀敵機？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하물며 파괴에 성공한다고 하더라도, 그 뒤는?","JPN":"仮に破壊できたとしても、その後はどうする？","ENG":"Even if you do succeed, what happens after that?","TWN":"況且，就算破壞成功，那之後呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자네의 단거리 공간 도약 능력은 잘 알고 있어.","JPN":"君の短距離空間跳躍能力はよく知っている。","ENG":"I am well aware of your short-distance space jump ability.","TWN":"我知道你有近距空間跳耀的能力。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 카운터라고 해도 우주에서 몸이 버틸 수 있을 지는…….","JPN":"しかしいくらカウンターだとしても、宇宙で体が耐えられるのか……","ENG":"But even if you are a Counter, your body can't possibly stand in space–","TWN":"但在太空中，就算是你制裁者，身體也不一定能承受……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장할! 사람 목숨 구하는데 이것저것 따지면 늦습니다!","JPN":"ああくそ！　人の命を助けるのにそんなこと言ってたら間に合わないんですよ！","ENG":"Dammit! Well, it'll be too late to save them if you keep on nitpicking like that!","TWN":"該死的！再這樣瞻前顧後的，就來不及救人了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 방법 말고 1시간 내로 필하모닉 홀로 다이브할 수 있는 다른 방법이 있습니까!","JPN":"じゃあ1時間以内にフィルハーモニーホールにダイブできる方法が他にあるんですか！","ENG":"Then is there another way to dive to Philharmonic Hall within an hour?!","TWN":"除此之外，還有其他可以在1小時躍入管弦樂廳的辦法嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그건……!","JPN":"それは……！","ENG":"That’s...!","TWN":"那個……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"절 보내주십시오. 힐데 전대장님!","JPN":"アタシを行かせてください。ヒルデ戦隊長！","ENG":"Send me up, Commander Hilde!","TWN":"讓我去吧。希爾德戰隊長！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"반드시…… 반드시 그 고철 덩어리를 지표면에 처박아버리겠습니다!","JPN":"必ず……必ずあの鉄くずの塊を地面に打ち込んでやります！","ENG":"I promise... to throw that hunk of junk down to the ground!","TWN":"我一定……一定會把那塊廢鐵撞爛！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 대신, 한 가지만 약속해주십시오.","JPN":"その代わりに、一つだけ約束してください。","ENG":"In return, promise me this.","TWN":"不過，請答應我一件事。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"필하모닉 홀에 갇힌 우리 전대원들을…… 꼭 구해주시는 겁니다.","JPN":"フィルハーモニーホールに閉じ込められたアタシの戦隊員を……絶対助けてくださいよ。","ENG":"You have to... rescue my division members trapped in Philharmonic Hall.","TWN":"我的戰隊員被困在了管弦樂廳……請一定要救救他們。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"알겠다. 약속하지.","JPN":"わかった。約束しよう。","ENG":"Understood. I give you my word.","TWN":"我知道了。我向你保證。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그리고 자네도 무사 귀환하길 빌겠다, 앨리스 전대장.","JPN":"そしてお前が無事帰還することを祈る、アリス戦隊長。","ENG":"Then, I hope for your safe return, Commander Alice.","TWN":"也希望你能平安歸來，艾莉絲戰隊長。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"걱정하지 마십시오.","JPN":"心配はご無用です。","ENG":"Don't worry.","TWN":"不用擔心。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"임무를 완수하고 보란 듯이 살아서 돌아올 테니까요.","JPN":"任務を完遂し、胸張って生還してみせますから。","ENG":"I'll complete my mission and return safe and sound.","TWN":"我會順利完成任務，毫髮無傷地活著回來的。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"소방관 시절, 대장님은 입버릇처럼 말했다.","JPN":"消防士の頃、隊長が口癖のように言っていたことがある。","ENG":"When I was a firefighter, my captain had a saying he would always say.","TWN":"在我還是消防員的時候，隊長常說……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"구조자의 목숨과 스스로의 목숨.","JPN":"救助者の命と自分の命。","ENG":"The rescuee's and the rescuer's lives.","TWN":"求救者和自己的生命。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"훌륭한 소방관이라면, 둘 다 구해낼 수 있어야 한다고.","JPN":"立派な消防士なら、両方とも救ってみせるものだと。","ENG":"An excellent firefighter knows how to save them both.","TWN":"一個優秀的消防員應該能夠在保障自身安全的前提下，盡力拯救求救者的生命。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"둘 중 어느 쪽도 쉽게 포기해서는 안 된다고.","JPN":"どっちも簡単に諦めてはいけないと。","ENG":"That we shouldn't easily give up on either.","TWN":"無論是哪一方都不應該被輕易放棄。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 요격에 성공한다면, 펜릴 전대는 반드시 우리 전대원들을 구해내겠지.","JPN":"アタシが迎撃に成功すれば、フェンリル戦隊は必ずアタシの戦隊員を助けてくれるはずだ。","ENG":"If I take that ship down, then the Fenrir Division will rescue my members no matter what.","TWN":"如果成功了，芬里爾戰隊就一定能救出我的戰隊員。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"전우들을 믿는 거야. 펜릴 전대는 무적이니까!","JPN":"戦友を信じるんだ。フェンリル戦隊は無敵だから！","ENG":"I trust them. Because the Fenrir Division is invincible!","TWN":"我相信我的戰友。因為芬里爾戰隊是無敵的！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"반드시 성공해야 해. 성공해서 펜릴에게 길을 열어 주는 거야.","JPN":"必ず成功させなければ。成功してフェンリルに道を開いてやるんだ。","ENG":"I must succeed and open the way for the Fenrir Division.","TWN":"拜託了。只有成功，才能為芬里爾開出一條道路。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"더는 후회 같은 걸 남기지 않도록…….","JPN":"もう二度と、後悔なんかしないように……","ENG":"So that I won't have any regrets...","TWN":"我不會再留下遺憾……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이번에야말로…… 모두를 구해내고, 웃으면서 녀석들을 맞이하는 거야.","JPN":"今度こそ、みんなを救い出して、笑顔でやつらを迎えるんだ。","ENG":"This time... I'll save them all and greet them all with a smile.","TWN":"這一次……我會拯救所有人，帶著微笑迎接他們歸來。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"타오르는 불꽃 속에서 홀로 살아 남아버렸던 날.","JPN":"燃え盛る炎の中から一人生き残ってしまったあの日。","ENG":"The day I survived alone within the crackling flames.","TWN":"從我獨自從那場熊熊燃燒的大火中倖存下來的那天後……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그 날 이후. 나는 줄곧 생각해 왔다.","JPN":"あの日からアタシはずっと考えていた。","ENG":"Ever since then, I've been thinking.","TWN":"那天之後，我一直在思考這個問題。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"만약, 둘 중에 하나를 반드시 선택해야 하는 상황이 온다면.","JPN":"もし、どちらかの命を選ばないといけない状況に置かれたら。","ENG":"If the situation came where I had to make a choice between one or the other...","TWN":"如果有一天，一定要在兩者之間做出選擇的話。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"그때가 온다면 나는…….","JPN":"そんな日が来たら、アタシは……","ENG":"If that time came, then I...","TWN":"到那時，我……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};